import{_ as a,o as r,c as e,a2 as o}from"./chunks/framework.Bjylvv1V.js";const u=JSON.parse('{"title":"지출 전표 입력","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scenarios/expense-voucher.md","filePath":"guide/scenarios/expense-voucher.md","lastUpdated":1772074398000}'),l={name:"guide/scenarios/expense-voucher.md"};function d(h,t,i,n,s,c){return r(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="지출-전표-입력" tabindex="-1">지출 전표 입력 <a class="header-anchor" href="#지출-전표-입력" aria-label="Permalink to &quot;지출 전표 입력&quot;">​</a></h1><blockquote><p><strong>소요 시간</strong>: 건당 약 5분 | <strong>난이도</strong>: ★★☆ | <strong>주기</strong>: 수시 (지출 발생 시)</p></blockquote><p>아파트 관리사무소에서 발생하는 각종 지출(관리 용역비, 시설 수선비, 사무용품 구매 등)을 회계 전표로 기록하는 프로세스입니다.</p><h2 id="전체-흐름" tabindex="-1">전체 흐름 <a class="header-anchor" href="#전체-흐름" aria-label="Permalink to &quot;전체 흐름&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 지출 증빙 확인       (1분)  → 영수증·세금계산서 등 증빙 확인</span></span>
<span class="line"><span>2. 전표 입력            (3분)  → 차변/대변 계정과목·금액 입력</span></span>
<span class="line"><span>3. 증빙 연결            (1분)  → 증빙 문서 첨부 (선택)</span></span>
<span class="line"><span>4. 저장 및 확인         (1분)  → 전표 저장·인쇄</span></span></code></pre></div><hr><h2 id="전표의-기본-개념" tabindex="-1">전표의 기본 개념 <a class="header-anchor" href="#전표의-기본-개념" aria-label="Permalink to &quot;전표의 기본 개념&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">전표란?</p><p>돈의 이동을 기록하는 장부입니다. 모든 거래는 **차변(받는 쪽)**과 **대변(주는 쪽)**으로 나누어 기록하며, 차변 합계와 대변 합계는 항상 같아야 합니다.</p></div><h3 id="전표-유형" tabindex="-1">전표 유형 <a class="header-anchor" href="#전표-유형" aria-label="Permalink to &quot;전표 유형&quot;">​</a></h3><table tabindex="0"><thead><tr><th>유형</th><th>코드</th><th>설명</th><th>예시</th></tr></thead><tbody><tr><td><strong>대체전표</strong></td><td>1</td><td>현금 이동 없는 거래</td><td>감가상각, 미수금 대체</td></tr><tr><td><strong>입금전표</strong></td><td>2</td><td>돈이 들어오는 거래</td><td>관리비 수납, 이자 수입</td></tr><tr><td><strong>출금전표</strong></td><td>3</td><td>돈이 나가는 거래</td><td>용역비 지급, 물품 구매</td></tr></tbody></table><h3 id="자주-사용하는-계정과목-지출" tabindex="-1">자주 사용하는 계정과목 (지출) <a class="header-anchor" href="#자주-사용하는-계정과목-지출" aria-label="Permalink to &quot;자주 사용하는 계정과목 (지출)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>계정과목</th><th>용도</th><th>차변/대변</th></tr></thead><tbody><tr><td>관리용역비</td><td>청소·경비 등 용역 대금</td><td>차변(비용)</td></tr><tr><td>수선유지비</td><td>시설 수선·보수 비용</td><td>차변(비용)</td></tr><tr><td>소모품비</td><td>사무용품·소모품 구매</td><td>차변(비용)</td></tr><tr><td>보통예금</td><td>은행 계좌에서 출금</td><td>대변(자산 감소)</td></tr><tr><td>미지급금</td><td>아직 지급하지 않은 대금</td><td>대변(부채 증가)</td></tr></tbody></table><hr><h2 id="_1단계-지출-증빙-확인-1분" tabindex="-1">1단계: 지출 증빙 확인 (1분) <a class="header-anchor" href="#_1단계-지출-증빙-확인-1분" aria-label="Permalink to &quot;1단계: 지출 증빙 확인 (1분)&quot;">​</a></h2><p>전표를 입력하기 전에 증빙 자료를 확인합니다.</p><h3 id="증빙-종류" tabindex="-1">증빙 종류 <a class="header-anchor" href="#증빙-종류" aria-label="Permalink to &quot;증빙 종류&quot;">​</a></h3><ul><li><strong>세금계산서</strong>: 사업자 간 거래 (부가세 포함)</li><li><strong>카드 매출전표</strong>: 법인카드 결제</li><li><strong>현금영수증</strong>: 현금 결제 시</li><li><strong>이체확인증</strong>: 계좌이체 시</li><li><strong>간이영수증</strong>: 소액 거래 (법정 한도 이내)</li></ul><h3 id="체크리스트" tabindex="-1">체크리스트 <a class="header-anchor" href="#체크리스트" aria-label="Permalink to &quot;체크리스트&quot;">​</a></h3><ul><li>[ ] 증빙 자료가 있는가?</li><li>[ ] 금액이 정확한가?</li><li>[ ] 날짜가 맞는가?</li><li>[ ] 공급받는 자(우리 단지) 정보가 정확한가?</li></ul><hr><h2 id="_2단계-전표-입력-3분" tabindex="-1">2단계: 전표 입력 (3분) <a class="header-anchor" href="#_2단계-전표-입력-3분" aria-label="Permalink to &quot;2단계: 전표 입력 (3분)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표입력 (ACCT2010)</p></blockquote><h3 id="절차" tabindex="-1">절차 <a class="header-anchor" href="#절차" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>전표입력 화면 진입</li><li><strong>전표일자</strong> 입력 (실제 거래일)</li><li>전표번호는 <strong>자동 부여</strong></li><li><strong>차변</strong> 입력: <ul><li>계정과목 선택 (예: 수선유지비)</li><li>금액 입력</li><li>적요 입력 (예: &quot;3월 엘리베이터 점검비&quot;)</li></ul></li><li><strong>대변</strong> 입력: <ul><li>계정과목 선택 (예: 보통예금)</li><li>금액 입력 (차변과 동일)</li><li>적요 입력</li></ul></li><li><strong>차변 합계 = 대변 합계</strong> 확인</li><li><strong>저장</strong> 클릭</li></ol><h3 id="입력-예시-엘리베이터-점검비-500-000원-계좌이체" tabindex="-1">입력 예시: 엘리베이터 점검비 500,000원 계좌이체 <a class="header-anchor" href="#입력-예시-엘리베이터-점검비-500-000원-계좌이체" aria-label="Permalink to &quot;입력 예시: 엘리베이터 점검비 500,000원 계좌이체&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>계정과목</th><th>적요</th><th>금액</th></tr></thead><tbody><tr><td><strong>차변</strong></td><td>수선유지비</td><td>3월 엘리베이터 점검비</td><td>500,000</td></tr><tr><td><strong>대변</strong></td><td>보통예금</td><td>3월 엘리베이터 점검비</td><td>500,000</td></tr></tbody></table><h3 id="입력-예시-사무용품-구매-100-000원-세금계산서-부가세-포함" tabindex="-1">입력 예시: 사무용품 구매 100,000원 (세금계산서, 부가세 포함) <a class="header-anchor" href="#입력-예시-사무용품-구매-100-000원-세금계산서-부가세-포함" aria-label="Permalink to &quot;입력 예시: 사무용품 구매 100,000원 (세금계산서, 부가세 포함)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>구분</th><th>계정과목</th><th>적요</th><th>금액</th></tr></thead><tbody><tr><td><strong>차변</strong></td><td>소모품비</td><td>사무용품 구매 (공급가)</td><td>90,909</td></tr><tr><td><strong>차변</strong></td><td>부가세대급금</td><td>사무용품 부가세</td><td>9,091</td></tr><tr><td><strong>대변</strong></td><td>보통예금</td><td>사무용품 대금 지급</td><td>100,000</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">빠른 입력 방법</p><p><strong>자동분개</strong> 기능을 활용하면 자주 사용하는 전표 패턴을 불러올 수 있습니다. 전표입력 화면에서 자동분개선택(ACCT2020) 버튼을 클릭하세요. 사전에 <a href="/acct/basic.html">기초정보</a> &gt; 자동분개등록(ACCT1050)에서 패턴을 등록해 두어야 합니다.</p></div><div class="tip custom-block"><p class="custom-block-title">적요코드 활용</p><p>적요를 매번 입력하기 번거로우면 <strong>적요코드</strong>를 사용하세요. 코드를 입력하면 미리 등록한 적요가 자동 입력됩니다.</p></div><hr><h2 id="_3단계-증빙-연결-1분-선택" tabindex="-1">3단계: 증빙 연결 (1분, 선택) <a class="header-anchor" href="#_3단계-증빙-연결-1분-선택" aria-label="Permalink to &quot;3단계: 증빙 연결 (1분, 선택)&quot;">​</a></h2><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표입력 &gt; 증빙연결 (ACCT2020)</p></blockquote><h3 id="절차-1" tabindex="-1">절차 <a class="header-anchor" href="#절차-1" aria-label="Permalink to &quot;절차&quot;">​</a></h3><ol><li>전표 입력 후 <strong>증빙연결</strong> 버튼 클릭</li><li>사전에 증빙관리에 등록된 증빙 선택</li><li>연결 완료</li></ol><h3 id="계좌거래내역-연결" tabindex="-1">계좌거래내역 연결 <a class="header-anchor" href="#계좌거래내역-연결" aria-label="Permalink to &quot;계좌거래내역 연결&quot;">​</a></h3><blockquote><p>전표입력 &gt; 계좌거래내역연결 (ACCT2020)</p></blockquote><p>아파트뱅크의 거래내역과 직접 연결할 수도 있습니다.</p><hr><h2 id="_4단계-저장-및-확인-1분" tabindex="-1">4단계: 저장 및 확인 (1분) <a class="header-anchor" href="#_4단계-저장-및-확인-1분" aria-label="Permalink to &quot;4단계: 저장 및 확인 (1분)&quot;">​</a></h2><ol><li><strong>저장</strong> 클릭 → 차변/대변 합계 일치 확인 후 저장됨</li><li>필요 시 전표 <strong>인쇄</strong></li></ol><h3 id="전표-수정이-필요한-경우" tabindex="-1">전표 수정이 필요한 경우 <a class="header-anchor" href="#전표-수정이-필요한-경우" aria-label="Permalink to &quot;전표 수정이 필요한 경우&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표입력 &gt; 전표찾기</p></blockquote><ol><li>전표찾기에서 해당 전표 검색 (기간, 계정, 적요, 금액으로 검색 가능)</li><li>전표 선택 후 수정</li><li>저장</li></ol><h3 id="전표-복사-이동" tabindex="-1">전표 복사/이동 <a class="header-anchor" href="#전표-복사-이동" aria-label="Permalink to &quot;전표 복사/이동&quot;">​</a></h3><table tabindex="0"><thead><tr><th>기능</th><th>설명</th></tr></thead><tbody><tr><td><strong>수정복사</strong></td><td>기존 전표를 복사하여 일부 수정 후 새 전표 생성</td></tr><tr><td><strong>전표복사</strong></td><td>다른 날짜로 전표 복제</td></tr><tr><td><strong>전표이동</strong></td><td>전표를 다른 날짜로 이동</td></tr></tbody></table><hr><h2 id="입력-확인-방법" tabindex="-1">입력 확인 방법 <a class="header-anchor" href="#입력-확인-방법" aria-label="Permalink to &quot;입력 확인 방법&quot;">​</a></h2><h3 id="분개장" tabindex="-1">분개장 <a class="header-anchor" href="#분개장" aria-label="Permalink to &quot;분개장&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 분개장 (ACCT2061)</p></blockquote><p>일별/월별 차변·대변 내역을 확인합니다.</p><h3 id="현금출납장" tabindex="-1">현금출납장 <a class="header-anchor" href="#현금출납장" aria-label="Permalink to &quot;현금출납장&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 현금출납장 (ACCT2090)</p></blockquote><p>현금 입출금과 잔액을 확인합니다.</p><h3 id="전표수정이력" tabindex="-1">전표수정이력 <a class="header-anchor" href="#전표수정이력" aria-label="Permalink to &quot;전표수정이력&quot;">​</a></h3><blockquote><p><strong>메뉴 경로</strong>: 회계 &gt; <a href="/acct/voucher.html">전표관리</a> &gt; 전표수정이력 (ACCT2054)</p></blockquote><p>전표의 수정·삭제 이력을 추적합니다.</p><hr><h2 id="자주-발생하는-문제" tabindex="-1">자주 발생하는 문제 <a class="header-anchor" href="#자주-발생하는-문제" aria-label="Permalink to &quot;자주 발생하는 문제&quot;">​</a></h2><h3 id="저장이-안-돼요" tabindex="-1">저장이 안 돼요 <a class="header-anchor" href="#저장이-안-돼요" aria-label="Permalink to &quot;저장이 안 돼요&quot;">​</a></h3><p><strong>원인</strong>: 차변 합계 ≠ 대변 합계 <strong>해결</strong>: 금액을 다시 확인하세요. 차변과 대변의 합계가 정확히 일치해야 저장됩니다.</p><h3 id="어떤-계정과목을-써야-할지-모르겠어요" tabindex="-1">어떤 계정과목을 써야 할지 모르겠어요 <a class="header-anchor" href="#어떤-계정과목을-써야-할지-모르겠어요" aria-label="Permalink to &quot;어떤 계정과목을 써야 할지 모르겠어요&quot;">​</a></h3><p><strong>원인</strong>: 회계 계정 체계에 익숙하지 않은 경우 <strong>해결</strong>: <a href="/acct/basic.html">기초정보</a> &gt; 계정과목코드관리(ACCT1020)에서 계정 목록을 확인하세요. 서울시회계·국토부회계 등 기준에 따라 다를 수 있습니다. 확실하지 않으면 기존에 유사한 거래의 전표를 전표찾기로 검색하여 참고하세요.</p><h3 id="이미-마감된-월에-전표를-입력해야-해요" tabindex="-1">이미 마감된 월에 전표를 입력해야 해요 <a class="header-anchor" href="#이미-마감된-월에-전표를-입력해야-해요" aria-label="Permalink to &quot;이미 마감된 월에 전표를 입력해야 해요&quot;">​</a></h3><p><strong>원인</strong>: 월마감 후 누락 전표 발견 <strong>해결</strong>: 관리자에게 월마감 해제를 요청하거나, 다음 달 날짜로 전표를 입력하세요.</p><h3 id="전표를-잘못-입력해서-삭제하고-싶어요" tabindex="-1">전표를 잘못 입력해서 삭제하고 싶어요 <a class="header-anchor" href="#전표를-잘못-입력해서-삭제하고-싶어요" aria-label="Permalink to &quot;전표를 잘못 입력해서 삭제하고 싶어요&quot;">​</a></h3><p><strong>원인</strong>: 오입력 <strong>해결</strong>: 전표찾기에서 해당 전표를 찾아 삭제하세요. 삭제 이력은 전표수정이력(ACCT2054)에 남습니다. 이미 관련 처리(수납 연계 등)가 된 전표는 역분개(반대 전표 입력)로 처리하는 것이 안전합니다.</p><hr><h2 id="관련-메뉴" tabindex="-1">관련 메뉴 <a class="header-anchor" href="#관련-메뉴" aria-label="Permalink to &quot;관련 메뉴&quot;">​</a></h2><ul><li><a href="/acct/voucher.html">전표관리</a> - 전표 입력·조회·수정 상세</li><li><a href="/acct/basic.html">기초정보</a> - 계정과목, 자동분개, 적요 관리</li><li><a href="/acct/ledger.html">장부관리</a> - 총계정원장, 보조부원장</li><li><a href="/bank/transfer.html">아파트뱅크 이체</a> - 이체 후 전표 생성</li><li><a href="/bank/evidence.html">아파트뱅크 증빙</a> - 세금계산서·영수증 관리</li></ul>`,70)])])}const b=a(l,[["render",d]]);export{u as __pageData,b as default};
